insert into artist (name, biography, photo)values (    'Леонардо да Винчи',    'Итальянский художник эпохи Возрождения, а также инженер, ученый и изобретатель. Создал «Мону Лизу» и «Тайную вечерю» и считается одним из самых влиятельных мастеров в истории искусства.',    X'');insert into artist (name, biography, photo)values (    'Винсент ван Гог',    'Нидерландский художник-постимпрессионист, известный яркой палитрой, эмоциональной выразительностью и свободной манерой письма. Среди его самых известных работ — «Звездная ночь» и серия «Подсолнухи».',    X'');insert into artist (name, biography, photo)values (    'Пабло Пикассо',    'Испанский художник, скульптор и график, один из ключевых мастеров XX века. Вместе с Жоржем Браком стал основоположником кубизма и за долгую карьеру радикально изменил язык современного искусства.',    X'');insert into artist (name, biography, photo)values (    'Фрида Кало',    'Мексиканская художница, прославившаяся автопортретами, в которых соединяются личная история, физическая боль, символика и мексиканская культура. Сегодня считается одной из самых узнаваемых фигур искусства XX века.',    X'');insert into artist (name, biography, photo)values (    'Альбрехт Дюрер',    'Немецкий художник, график и теоретик искусства эпохи Северного Возрождения. Прославился гравюрами, живописными автопортретами и стремлением соединить художественную практику с точными научными наблюдениями.',    X'');insert into artist (name, biography, photo)values (    'Рембрандт ван Рейн',    'Нидерландский живописец и офортист XVII века, один из величайших мастеров барокко. Известен глубокими психологическими портретами, драматической светотенью и многочисленными автопортретами.',    X'');insert into artist (name, biography, photo)values (    'Поль Гоген',    'Французский художник-постимпрессионист, чьи поиски яркого цвета, упрощенной формы и символического образа сильно повлияли на модернизм. Значительную часть жизни он 